"""Benchmark Results page — browse and compare stored benchmark artifacts.

Accepts either:
  * A directory of benchmark artifact JSON files (``results.json`` per run), or
  * A consolidated ``batch_summary.json`` file generated by the PyPIELM CLI.

Displays:
  * Interactive leaderboard table (sortable by any metric).
  * Bar / heatmap comparison across models and PDE tasks.
  * Per-run drill-down: config, metrics, raw download.
"""

from __future__ import annotations

import json
import sys
from pathlib import Path

import numpy as np
import pandas as pd
import streamlit as st

sys.path.insert(0, str(Path(__file__).parent.parent))
from utils.plotting import plot_comparison_bar

st.set_page_config(page_title="Benchmark Results · PyPIELM", page_icon="🏆", layout="wide")

st.title("🏆 Benchmark Results")

# ---------------------------------------------------------------------------
# Data source selection
# ---------------------------------------------------------------------------

st.markdown("### Load benchmark results")
source_mode = st.radio(
    "Source",
    ["Upload results.json file(s)", "Paste JSON"],
    horizontal=True,
)

records: list[dict] = []

if source_mode == "Upload results.json file(s)":
    uploaded_files = st.file_uploader(
        "Upload one or more `results.json` files (one per benchmark run)",
        type="json",
        accept_multiple_files=True,
    )
    for f in uploaded_files or []:
        try:
            data = json.loads(f.read())
            # Support both single-run and batch_summary formats
            if isinstance(data, list):
                records.extend(data)
            elif "runs" in data:
                records.extend(data["runs"])
            else:
                records.append(data)
        except Exception as exc:
            st.warning(f"Could not parse `{f.name}`: {exc}")

else:  # paste JSON
    raw = st.text_area(
        "Paste a JSON array of run records or a batch_summary object",
        height=200,
        placeholder='[{"model": "CorePIELM", "task": "poisson_classic", "metrics": {"relative_l2": 0.21}}, ...]',
    )
    if raw.strip():
        try:
            data = json.loads(raw)
            if isinstance(data, list):
                records = data
            elif "runs" in data:
                records = data["runs"]
            else:
                records = [data]
        except Exception as exc:
            st.error(f"Invalid JSON: {exc}")

# ---------------------------------------------------------------------------
# Demo data fallback
# ---------------------------------------------------------------------------

if not records:
    st.info(
        "No results loaded yet.  \n"
        "Upload `results.json` files from a `python -m pypielm run` experiment, "
        "or use the **demo data** below.",
        icon="ℹ️",
    )
    if st.button("Load demo results"):
        # Synthetic benchmark data for demonstration
        _MODELS = ["VanillaPIELM", "CorePIELM", "BayesianPIELM", "GFFPIELM", "CurriculumPIELM"]
        _TASKS  = ["poisson_1d", "poisson_2d", "heat_1d", "burgers_1d"]
        rng = np.random.default_rng(42)
        for m in _MODELS:
            for t in _TASKS:
                base = rng.uniform(0.05, 0.5)
                records.append({
                    "model":  m,
                    "task":   t,
                    "seed":   42,
                    "config": {"hidden_dim": 200},
                    "metrics": {
                        "relative_l2": float(base),
                        "rmse":        float(base * 0.5),
                        "r2":          float(1.0 - base),
                    },
                })
    if not records:
        st.stop()

# ---------------------------------------------------------------------------
# Flatten records into a DataFrame
# ---------------------------------------------------------------------------

rows = []
for r in records:
    row: dict = {}
    row["model"] = r.get("model", r.get("model_name", "?"))
    row["task"]  = r.get("task",  r.get("dataset",   "?"))
    row["seed"]  = r.get("seed",  "-")
    metrics = r.get("metrics", {})
    row.update(metrics)
    # flatten config top-level keys
    for k, v in r.get("config", {}).items():
        if isinstance(v, (int, float, str, bool)):
            row[f"cfg.{k}"] = v
    rows.append(row)

df = pd.DataFrame(rows)
metric_cols = [c for c in df.columns if c not in ("model", "task", "seed") and not c.startswith("cfg.")]

# ---------------------------------------------------------------------------
# Leaderboard table
# ---------------------------------------------------------------------------

st.divider()
st.markdown("### Leaderboard")

sort_metric = st.selectbox("Sort by", metric_cols, key="sort_metric") if metric_cols else None
asc = st.checkbox("Lower is better", value=True)

if sort_metric and sort_metric in df.columns:
    df_sorted = df.sort_values(sort_metric, ascending=asc).reset_index(drop=True)
else:
    df_sorted = df.reset_index(drop=True)

# Highlight best per task
st.dataframe(
    df_sorted,
    use_container_width=True,
    hide_index=True,
)

st.download_button(
    "⬇ Download leaderboard CSV",
    data=df_sorted.to_csv(index=False),
    file_name="pypielm_leaderboard.csv",
    mime="text/csv",
)

# ---------------------------------------------------------------------------
# Model comparison bar chart
# ---------------------------------------------------------------------------

if metric_cols and len(df["model"].unique()) > 1:
    st.divider()
    st.markdown("### Model comparison")

    col_t, col_m = st.columns(2)
    with col_t:
        task_filter = st.selectbox(
            "Task filter", ["all"] + sorted(df["task"].unique().tolist())
        )
    with col_m:
        cmp_metric = st.selectbox("Metric", metric_cols, key="cmp_metric")

    df_filt = df if task_filter == "all" else df[df["task"] == task_filter]
    agg = df_filt.groupby("model")[cmp_metric].mean().reset_index()

    fig = plot_comparison_bar(
        agg["model"].tolist(),
        agg[cmp_metric].tolist(),
        metric_name=cmp_metric,
        lower_is_better=asc,
    )
    st.pyplot(fig, use_container_width=True)

# ---------------------------------------------------------------------------
# Heatmap — model × task
# ---------------------------------------------------------------------------

if metric_cols and len(df["task"].unique()) > 1:
    st.divider()
    st.markdown("### Heatmap — model × task")

    heat_metric = st.selectbox("Metric", metric_cols, key="heat_metric")
    pivot = df.pivot_table(index="model", columns="task", values=heat_metric, aggfunc="mean")

    import matplotlib
    matplotlib.use("Agg")
    import matplotlib.pyplot as plt

    fig2, ax = plt.subplots(figsize=(max(6, pivot.shape[1] * 1.2), max(3, pivot.shape[0] * 0.6)))
    im = ax.imshow(pivot.values, aspect="auto", cmap="RdYlGn_r")
    plt.colorbar(im, ax=ax, fraction=0.046, label=heat_metric)
    ax.set_xticks(range(pivot.shape[1]))
    ax.set_xticklabels(pivot.columns, rotation=30, ha="right", fontsize=9)
    ax.set_yticks(range(pivot.shape[0]))
    ax.set_yticklabels(pivot.index, fontsize=9)
    for i in range(pivot.shape[0]):
        for j in range(pivot.shape[1]):
            v = pivot.values[i, j]
            if not np.isnan(v):
                ax.text(j, i, f"{v:.3g}", ha="center", va="center", fontsize=8,
                        color="white" if v > pivot.values.mean() else "black")
    ax.set_title(f"{heat_metric} — lower is better" if asc else f"{heat_metric} — higher is better")
    fig2.tight_layout()
    st.pyplot(fig2, use_container_width=True)
